SELECT /* base.ec.mb :: MbMemberGroup :: selectList */ g.* , ste.site_nm AS site_nm FROM mb_member_group g LEFT JOIN sy_site ste ON ste.site_id = g.site_id
ORDER BY g.member_group_id ASC ORDER BY g.member_group_id DESC ORDER BY g.group_nm ASC ORDER BY g.group_nm DESC ORDER BY g.reg_date ASC ORDER BY g.reg_date DESC ORDER BY g.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.mb :: MbMemberGroup :: selectPageList */ g.* , ste.site_nm AS site_nm FROM mb_member_group g LEFT JOIN sy_site ste ON ste.site_id = g.site_id
ORDER BY g.member_group_id ASC ORDER BY g.member_group_id DESC ORDER BY g.group_nm ASC ORDER BY g.group_nm DESC ORDER BY g.reg_date ASC ORDER BY g.reg_date DESC ORDER BY g.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE mb_member_group /* base.ec.mb :: MbMemberGroup :: updateSelective */
site_id = #{siteId}, group_nm = #{groupNm}, group_memo = #{groupMemo}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE member_group_id = #{memberGroupId}
